export class BotCommand {
    get aliases() {
        return [];
    }
    match(line, prefix) {
        let [command, ...params] = line.split(' ');
        if (!command.startsWith(prefix)) {
            return null;
        }
        command = command.slice(prefix.length);
        if (command === this.name || this.aliases.includes(command)) {
            return params;
        }
        return null;
    }
}
